firmware_template.source:
#include "wifi_station.h"
static bool _connected = false;
void wifi_setup(const char* ssid, const char* pass) {
  WiFi.mode(WIFI_STA);
  WiFi.begin(ssid, pass);
  Serial.printf("[wifi] Connecting to %s", ssid);
  int retries = 0;
  while (WiFi.status() != WL_CONNECTED && retries < 40) {
    delay(500); Serial.print("."); retries++;
  }
  if (WiFi.status() == WL_CONNECTED) {
    _connected = true;
    Serial.printf("\n[wifi] OK IP=%s RSSI=%d\n", WiFi.localIP().toString().c_str(), WiFi.RSSI());
  } else {
    Serial.println("\n[wifi] FAILED!");
  }
}
void wifi_loop() {
  _connected = (WiFi.status() == WL_CONNECTED);
}
bool wifi_connected() { return _connected; }
String wifi_get_ip() { return WiFi.localIP().toString(); }
int wifi_get_rssi() { return WiFi.RSSI(); }
